#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-06-11

# Test: Every agent declaring Agent(<name>) in tools: frontmatter must
# document that delegation in a "## Delegation" body section that
# mentions each declared sub-agent.
#
# Why this exists (CC 2.1.172 nested sub-agents):
#   Since CC 2.1.172, sub-agents can spawn their own sub-agents (5 levels
#   deep) — Agent(...) declarations are now live chains, not decoration.
#   Models rarely use tools their prompt never mentions, so an agent with
#   an undocumented Agent(X) declaration effectively never delegates.
#   This guard keeps the declaration and the body documentation in sync:
#   add a sub-agent -> document when to delegate to it (or the test
#   fails CI instead of the capability silently going unused).

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
REPO_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"
AGENTS_DIR="$REPO_ROOT/src/agents"

FAILED=0
CHECKED=0

echo "=== Agent delegation docs: Agent(...) declarations documented (CC 2.1.172) ==="
echo ""

for agent_file in "$AGENTS_DIR"/*.md; do
  agent_name=$(basename "$agent_file" .md)

  case "$agent_name" in
    README|INDEX|CONTRIBUTING) continue ;;
  esac

  # Frontmatter only — Agent(...) mentions in the body don't count as declarations.
  frontmatter=$(awk '/^---$/{n++; next} n==1{print} n>=2{exit}' "$agent_file")
  mapfile -t refs < <(printf '%s\n' "$frontmatter" \
    | grep -oE 'Agent\([a-zA-Z0-9:_-]+\)' \
    | sed -E 's/Agent\(([^)]+)\)/\1/' | sort -u)

  [ "${#refs[@]}" -eq 0 ] && continue
  CHECKED=$((CHECKED + 1))

  if ! grep -qE '^##+ Delegation' "$agent_file"; then
    echo "FAIL: $agent_name declares Agent(${refs[*]}) but has no '## Delegation' section"
    FAILED=1
    continue
  fi

  # Each declared sub-agent must be mentioned somewhere in the Delegation section.
  delegation_section=$(awk '/^##+ Delegation/{found=1; print; next} found && /^##+ /{exit} found{print}' "$agent_file")
  for ref in "${refs[@]}"; do
    # Grants must use the runtime-registry name: bare Agent(name) fails at
    # dispatch ("Agent type 'name' not found") — live-verified, #2371.
    case "$ref" in
      *:*) ;;
      *)
        echo "FAIL: $agent_name declares bare Agent($ref) — runtime registry only resolves namespaced types (use Agent(ork:$ref), #2371)"
        FAILED=1
        ;;
    esac
    if ! printf '%s\n' "$delegation_section" | grep -q "$ref"; then
      echo "FAIL: $agent_name's Delegation section does not mention declared sub-agent '$ref'"
      FAILED=1
    fi
  done
done

echo ""
echo "Checked $CHECKED agent(s) with Agent(...) declarations."

# Self-decay floor: agents with Agent(...) grants exist today, so extracting
# zero declarations means the frontmatter/regex extraction silently broke —
# the guard would pass forever while checking nothing.
if [ "$CHECKED" -eq 0 ]; then
  echo "FAIL: guard extracted zero Agent() declarations — extraction regex broken?"
  FAILED=1
fi

if [ "$FAILED" -eq 1 ]; then
  echo "RESULT: FAIL"
  exit 1
fi

echo "RESULT: PASS"
